import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
// Importăm stilurile pentru layout-ul cu 3 pătrate
import './ProfessorPage.css';
// Importăm și stilurile specifice (dacă mai e nevoie de ele, ex. .loading-message)
import "./StudentPage.css";

interface Assignment {
    assid: number;
    asstitle: string;
    description: string;
    createdat: string; // Data va veni ca string
    fileUrl: string;
}

export default function StudentPage() {
    const [assignments, setAssignments] = useState<Assignment[]>([]);
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const token = localStorage.getItem("token");

        axios.get<Assignment[]>('http://localhost:9090/api/assignments/student/me', {
            headers: { Authorization: `Bearer ${token}` }
        })
            .then(response => {
                setAssignments(response.data);
                setIsLoading(false);
            })
            .catch(err => {
                console.error("Eroare la preluarea temelor:", err);
                setError("Nu am putut încărca temele. Te rog, încearcă mai târziu.");
                setIsLoading(false);
            });
    }, []); // Se execută o singură dată

    const handleAssignmentClick = (id: number) => {
        // Am schimbat ruta pentru a se potrivi cu logica de vizualizare (cea cu imaginea)
        navigate(`/assignment-view/${id}`);
    };

    const renderContent = () => {
        if (isLoading) {
            // Folosim stilul din ProfessorPage (ProfilePage.css) care e vizibil pe fundal întunecat
            return <p className="loading-message">Se încarcă temele...</p>;
        }

        if (error) {
            // Folosim stilul din ProfessorPage (ProfilePage.css)
            return <p className="error-message">{error}</p>;
        }

        if (assignments.length === 0) {
            // Folosim stilul din ProfessorPage (ProfilePage.css)
            return <p className="loading-message">Nu ai primit nicio temă încă.</p>;
        }

        return (
            // --- MODIFICARE CRITICĂ ---
            // Folosim clasa 'assignment-table-prof' (din ProfilePage.css)
            // care are text alb, pentru fundalul întunecat
            <table className="assignment-table-prof">
                <thead>
                <tr>
                    <th>Titlu Tema</th>
                    <th>Data Primirii</th>
                </tr>
                </thead>
                <tbody>
                {assignments.map((tema) => (
                    <tr
                        key={tema.assid}
                        onClick={() => handleAssignmentClick(tema.assid)}
                        className="clickable-row" // Acest stil e în StudentPage.css, dar hover-ul din .assignment-table-prof e mai important
                    >
                        <td>{tema.asstitle}</td>
                        <td>{new Date(tema.createdat).toLocaleDateString('ro-RO')}</td>
                    </tr>
                ))}
                </tbody>
            </table>
        );
    };

    return (
        // Am șters div-ul '.student-page' și l-am înlocuit
        // direct cu structura din ProfessorPage
        <div className="professor-page-container">
            { /*<VideoBackground /> */}

            {/* --- CONȚINUTUL ESTE ACUM AICI --- */}
            <div className="Patrat_stanga">
                {/* Am mutat titlul și tabelul aici */}
                <h2>Temele Mele</h2>
                {renderContent()}
            </div>

            <div className="Patrat_mijloc">
                {/* TODO: Poți adăuga Testele aici, de exemplu */}
                <h3>Testele Mele</h3>
            </div>

            <div className="Patrat_dreapta">
                {/* TODO: Alt conținut */}
            </div>
        </div>
    );
}
